import ipaddress
import socket
from urllib.parse import urlparse

import requests


class URLFetchError(Exception):
    pass


def _is_public_ip(ip: str) -> bool:
    addr = ipaddress.ip_address(ip)
    return not (
        addr.is_private
        or addr.is_loopback
        or addr.is_link_local
        or addr.is_multicast
        or addr.is_reserved
        or addr.is_unspecified
    )


def _resolve_public_addresses(hostname: str) -> list[str]:
    try:
        infos = socket.getaddrinfo(hostname, None, type=socket.SOCK_STREAM)
    except socket.gaierror as e:
        raise URLFetchError(f"Failed to resolve hostname: {hostname}") from e

    addresses = []
    for info in infos:
        ip = info[4][0]
        if _is_public_ip(ip):
            addresses.append(ip)

    if not addresses:
        raise URLFetchError("Hostname does not resolve to a public IP address")

    return list(dict.fromkeys(addresses))


def fetch_url_content(url: str, timeout: float = 5.0, max_bytes: int = 1_000_000) -> str:
    parsed = urlparse(url)

    if parsed.scheme not in ("http", "https"):
        raise URLFetchError("Only http and https URLs are allowed")

    if not parsed.hostname:
        raise URLFetchError("URL must include a valid hostname")

    _resolve_public_addresses(parsed.hostname)

    headers = {
        "User-Agent": "WebhookIntegrationFetcher/1.0",
        "Accept": "text/*,application/json,application/xml;q=0.9,*/*;q=0.1",
    }

    try:
        with requests.get(
            url,
            headers=headers,
            timeout=timeout,
            allow_redirects=False,
            stream=True,
        ) as response:
            response.raise_for_status()

            content_type = response.headers.get("Content-Type", "").lower()
            if "text" not in content_type and "json" not in content_type and "xml" not in content_type:
                raise URLFetchError(f"Unsupported content type: {content_type or 'unknown'}")

            chunks = []
            total = 0
            for chunk in response.iter_content(chunk_size=8192, decode_unicode=True):
                if not chunk:
                    continue
                total += len(chunk.encode(response.encoding or "utf-8", errors="ignore"))
                if total > max_bytes:
                    raise URLFetchError("Response exceeds maximum allowed size")
                chunks.append(chunk)

            content = "".join(chunks)
            print(content)
            return content

    except requests.RequestException as e:
        raise URLFetchError(f"Request failed: {e}") from e